<?php require_once __DIR__.'/../../includes/bootstrap.php'; require_login(); use app\Services\MemberService; $svc=new MemberService(); $errors=[]; $row=[]; if('create'==='edit'){ $id=(int)($_GET['id']??0); $row=$svc->find($id); if(!$row) include PUBLIC_PATH.'/404.php'; } if($_SERVER['REQUEST_METHOD']==='POST'){ $r=('create'==='edit')?$svc->save($_POST,$id):$svc->save($_POST); if($r['ok']){ flash('success','Đã lưu thành viên'); redirect_to('members/index.php'); } $errors=$r['errors']??[]; $row=array_merge($row,$_POST); } $title='Thêm thành viên'; include ROOT_PATH.'/includes/header.php'; ?><h1 class='h3 mb-3'>Thêm thành viên</h1><div class="card"><div class="card-body"><form method="post" class="row g-3"><div class="col-md-4"><label class="form-label required">Mã thành viên</label><input name="member_code" class="form-control" value="<?= e($row['member_code']??'') ?>"><div class="text-danger small"><?= e($errors['member_code']??'') ?></div></div><div class="col-md-8"><label class="form-label required">Họ tên</label><input name="full_name" class="form-control" value="<?= e($row['full_name']??'') ?>"><div class="text-danger small"><?= e($errors['full_name']??'') ?></div></div><div class="col-md-4"><label class="form-label">Mã sinh viên</label><input name="student_code" class="form-control" value="<?= e($row['student_code']??'') ?>"></div><div class="col-md-4"><label class="form-label">Lớp</label><input name="class_name" class="form-control" value="<?= e($row['class_name']??'') ?>"></div><div class="col-md-4"><label class="form-label">Ngành</label><input name="major" class="form-control" value="<?= e($row['major']??'') ?>"></div><div class="col-md-4"><label class="form-label">SĐT</label><input name="phone" class="form-control" value="<?= e($row['phone']??'') ?>"></div><div class="col-md-4"><label class="form-label">Email</label><input type="email" name="email" class="form-control" value="<?= e($row['email']??'') ?>"><div class="text-danger small"><?= e($errors['email']?